mapper.insert:
insert into oa_task (
    task_title, task_type, publisher_id, publisher_name, assignee_id, assignee_name, priority_level, task_status, start_time, due_time, content, create_by, create_time
) values (
    #{taskTitle}, #{taskType}, #{publisherId}, #{publisherName}, #{assigneeId}, #{assigneeName}, #{priorityLevel}, #{taskStatus}, #{startTime}, #{dueTime}, #{content}, #{createBy}, sysdate()
)

mapper.select:
select record_id, task_id, operator_id, operator_name, record_type, record_content, create_time
from oa_task_record
where task_id = #{taskId}
  and exists (
      select 1
      from oa_task
      where task_id = #{taskId}
        and (publisher_id = #{userId} or assignee_id = #{userId} or create_by = 'admin' or assignee_name = #{username})
  )
order by record_id desc

mapper.insert:
insert into oa_task_record (
    task_id, operator_id, operator_name, record_type, record_content, create_time
) values (
    #{taskId}, #{operatorId}, #{operatorName}, #{recordType}, #{recordContent}, sysdate()
)
